import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.MalformedURLException;
import java.net.URL;
import java.util.Scanner;

public class HttpClient {
    private static final String BASE_URL = "https://example.com"; // Replace with your cloud API URL
    private static final String LOCAL_NETWORK_BASE_URL = "http://192.168.x.x"; // Replace with your local network IP address

    public static void main(String[] args) throws IOException {
        HttpURLConnection connection = null;
        try {
            URL url = new URL(BASE_URL + "/api/v1/devices");
            connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("GET");
            connection.setDoOutput(true);
            connection.connect();

            if (connection.getResponseCode() == 200) {
                BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            } else {
                System.out.println("Error: " + connection.getResponseCode());
            }
        } catch (MalformedURLException e) {
            e.printStackTrace();
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
    }
}